mapper.select:
select 
from batch.file_record
where tenant_id = #{tenantId}
  and id = #{fileId}

select count(1)
from batch.file_record
where tenant_id = #{tenantId}
  and coalesce(storage_bucket, '') = coalesce(#{storageBucket}, '')
  and storage_path = #{storagePath}

select 
from batch.file_template_config
where tenant_id = #{tenantId}
  and template_code = #{templateCode}
  and enabled = true
  and is_deleted = false

    and template_type = #{templateType}

order by version desc
limit 1

select 
from batch.file_channel_config
where tenant_id = #{tenantId}
  and channel_code = #{channelCode}
  and enabled = true
  and is_deleted = false

select id
from batch.pipeline_definition
where tenant_id = #{tenantId}
  and job_code = #{jobCode}
order by version desc
limit 1

mapper.insert:
insert into batch.pipeline_definition (
    tenant_id, job_code, pipeline_name, pipeline_type,
    worker_group, version, enabled, description
) values (
    #{tenantId}, #{jobCode}, #{pipelineName}, #{pipelineType},
    #{workerGroup}, 1, true, #{description}
)

mapper.select:
select from batch.pipeline_step_definition where pipeline_definition_id = #{pipelineDefinitionId}
and enabled = true
order by step_order asc, step_code asc

mapper.insert:
insert into batch.pipeline_step_definition (
    pipeline_definition_id, step_code, step_name, stage_code, step_order,
    impl_code, step_params, timeout_seconds, retry_policy, retry_max_count, enabled
) values (
    #{pipelineDefinitionId}, #{stepCode}, #{stepName}, #{stageCode}, #{stepOrder},
    #{implCode}, #{stepParamsJson,jdbcType=VARCHAR}::jsonb, #{timeoutSeconds}, #{retryPolicy}, #{retryMaxCount}, #{enabled}
)

mapper.select:
select coalesce(max(run_seq), 0) + 1
from batch.pipeline_step_run
where pipeline_instance_id = #{pipelineInstanceId}
  and step_code = #{stepCode}

select step_code
from (
    select step_code,
           step_status,
           row_number() over (
               partition by step_code
               order by run_seq desc, id desc
           ) as rn
    from batch.pipeline_step_run
    where pipeline_instance_id = #{pipelineInstanceId}
) latest
where latest.rn = 1
  and latest.step_status = 'SUCCESS'

mapper.insert:
with step_run_lock as (
    select pg_advisory_xact_lock(
        hashtextextended(
            concat('pipeline_step_run:', #{pipelineInstanceId}, ':', #{stepCode}),
            0
        )
    )
),
next_seq as (
    select coalesce(max(run_seq), 0) + 1 as run_seq
    from batch.pipeline_step_run, step_run_lock
    where pipeline_instance_id = #{pipelineInstanceId}
      and step_code = #{stepCode}
)
insert into batch.pipeline_step_run (
    pipeline_instance_id, step_code, stage_code, run_seq,
    step_status, input_summary, started_at
)
select
    #{pipelineInstanceId}, #{stepCode}, #{stageCode}, next_seq.run_seq,
    #{stepStatus}, #{inputSummaryJson,jdbcType=VARCHAR}::jsonb, current_timestamp
from next_seq

mapper.select:
select coalesce(max(file_generation_no), 0)
from batch.file_record
where tenant_id = #{tenantId}
  and file_code = #{fileCode}

mapper.update:
update batch.file_record
set is_latest = false,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and file_code = #{fileCode}
  and is_latest = true

mapper.select:
select file_status
from batch.file_record
where id = #{fileId}

select 
from batch.file_error_record
where tenant_id = #{tenantId}

    and file_id = #{fileId}


    and error_code = #{errorCode}


    and error_stage = #{errorStage}

order by id desc
limit #{limit}
